  if (n == scope.getRootNode()) return;

  if (n.getType() == Token.LP && parent == scope.getRootNode()) {
    handleFunctionInputs(parent);
    return;
  }

  attachLiteralTypes(n);
  switch (n.getType()) {
    case Token.FUNCTION:
      // Check if this is a function expression being assigned to a property
      if (parent.getType() == Token.ASSIGN) {
        // Handle function assignments to properties (like ns.a = function(b) {})
        defineDeclaredFunction(n, parent);
      } else if (parent.getType() != Token.NAME) {
        // Handle other function expressions (not named function declarations)
        defineDeclaredFunction(n, parent);
      }
      break;
    case Token.CATCH:
      defineCatch(n, parent);
      break;
    case Token.VAR:
      defineVar(n, parent);
      break;
  }
}

