public static String getNamespaceURI(Node node) {
    if (node instanceof Document) {
        node = ((Document) node).getDocumentElement();
    }

    Element element = (Element) node;

    String uri = element.getNamespaceURI();
    if (uri == null) {
        String prefix = getPrefix(node);
        String qname = prefix == null ? "xmlns" : "xmlns:" + prefix;

        Node aNode = node;
        while (aNode != null) {
            if (aNode.getNodeType() == Node.ELEMENT_NODE) {
                Attr attr = ((Element) aNode).getAttributeNode(qname);
                if (attr != null) {
                    return attr.getValue();
                }
            }
            aNode = aNode.getParentNode();
        }
        return null;
    }

    // Fix: Check if this element explicitly declares an empty namespace
    if (uri.length() == 0) {
        // Check if this element has an xmlns attribute with empty value
        if (element.hasAttribute("xmlns") && element.getAttribute("xmlns").length() == 0) {
            return null; // Treat as no namespace
        }

        // Check if any ancestor explicitly reset the namespace to empty
        Node parent = element.getParentNode();
        while (parent != null && parent.getNodeType() == Node.ELEMENT_NODE) {
            Element parentElem = (Element) parent;
            if (parentElem.hasAttribute("xmlns") && parentElem.getAttribute("xmlns").length() == 0) {
                // Found an ancestor that reset namespace to empty, so this element is truly in no namespace
                return null;
            }
            parent = parent.getParentNode();
        }
    }

    return uri;
}

