            sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);
            pos = text.substring(pos).trim().indexOf(' ') == -1 ? -1 : pos;
        } else {
            pos = -1;
        }

        if (pos == -1) {
            sb.append(text);
            return sb;
        }
    }
}

