        fPrime2Integral += fPrime2StepIntegral;

        sx2 += x * x;
        sy2 += f2Integral * f2Integral;
        sxy += x * f2Integral;
        sxz += x * fPrime2Integral;
        syz += f2Integral * fPrime2Integral;
    }

    // compute the amplitude and pulsation coefficients
    double c1 = sy2 * sxz - sxy * syz;
    double c2 = sxy * sxz - sx2 * syz;
    double c3 = sx2 * sy2 - sxy * sxy;
    if ((c1 / c2 < 0) || (c2 / c3 < 0) || (c1 <= 0) || (c2 <= 0) || (c3 <= 0)) {
        final int last = observations.length - 1;
        // Range of the observations, assuming that the
        // observations are sorted.
        final double xRange = observations[last].getX() - observations[0].getX();
        if (xRange == 0) {
            throw new ZeroException();
        }

        // Use the RMS value as a better estimate for amplitude
        double ySumSquares = 0;
        double yMean = 0;
        for (int i = 0; i < observations.length; i++) {
            final double y = observations[i].getY();
            yMean += y;
            ySumSquares += y * y;
        }
        yMean /= observations.length;

        // Amplitude estimate using RMS (root mean square) of centered data
        double yRms = FastMath.sqrt(ySumSquares / observations.length - yMean * yMean);
        a = FastMath.sqrt(2) * yRms; // For a sine wave, RMS = amplitude / sqrt(2)

        // Estimate omega using the number of zero crossings
        int zeroCrossings = 0;
        boolean previousPositive = observations[0].getY() - yMean >= 0;
        for (int i = 1; i < observations.length; i++) {
            boolean currentPositive = observations[i].getY() - yMean >= 0;
            if (previousPositive != currentPositive) {
                zeroCrossings++;
                previousPositive = currentPositive;
            }
        }

        if (zeroCrossings > 0) {
            // Each zero crossing represents half a period
            double averagePeriod = 2 * xRange / zeroCrossings;
            omega = 2 * Math.PI / averagePeriod;
        } else {
            // Fallback: use the full range as one period
            omega = 2 * Math.PI / xRange;
        }
    } else {
        // In some ill-conditioned cases (cf. MATH-844), the guesser
        // procedure cannot produce sensible results.
        a = FastMath.sqrt(c1 / c2);
        omega = FastMath.sqrt(c2 / c3);
    }
}

