  TemplateTypeMap fnTypeMap = fnType.getTemplateTypeMap();
  Map<TemplateType, JSType> filteredInferred = Maps.newHashMap();
  for (Map.Entry<TemplateType, JSType> entry : inferred.entrySet()) {
