    /**
     * Security fix: Check if the type is allowed for deserialization
     * Blocks known dangerous types that could lead to remote code execution
     */
    protected void _checkIfValidType(DeserializationContext ctxt, JavaType type) 
        throws JsonMappingException 
    {
        Class<?> rawClass = type.getRawClass();
        String className = rawClass.getName();

        // Block known dangerous types
        if (_isBlockedClass(rawClass)) {
            String msg = String.format("Blocked deserialization of type %s for security reasons", 
                className);
            throw ctxt.mappingException(msg);
        }
    }

    /**
     * Security fix: Check if a class is in the blocked list
     */
    protected boolean _isBlockedClass(Class<?> clazz) {
        String className = clazz.getName();

        // Block java.lang.Class and related types that could enable code execution
        if (className.startsWith("java.lang.Class") ||
            className.startsWith("javax.management.") ||
            className.startsWith("java.rmi.") ||
            className.startsWith("org.springframework.") ||
            className.startsWith("org.apache.commons.collections.") ||
            className.startsWith("com.sun.") ||
            className.equals("java.lang.ProcessBuilder") ||
            className.equals("java.lang.Runtime") ||
            className.equals("java.lang.System") ||
            className.equals("java.lang.Thread") ||
            className.equals("java.sql.DriverManager") ||
            className.equals("java.util.logging.") ||
            className.equals("org.slf4j.") ||
            className.equals("ch.qos.logback.")) {
            return true;
        }

        // Additional checks for arrays of blocked types
        if (clazz.isArray()) {
            return _isBlockedClass(clazz.getComponentType());
        }

        return false;
    }

