protected StringBuffer renderWrappedText(StringBuffer sb, int width, 
                                         int nextLineTabStop, String text)
{
    int pos = findWrapPos(text, width, 0);

    if (pos == -1)
    {
        sb.append(rtrim(text));

        return sb;
    }
    sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);

    if (nextLineTabStop >= width)
    {
        // stops infinite loop happening
        throw new IllegalStateException("Total width is less than the width of the argument and indent " + 
                                        "- no room for the description");
    }

    // all following lines must be padded with nextLineTabStop space 
    // characters
    final String padding = createPadding(nextLineTabStop);

    while (true)
    {
        text = padding + text.substring(pos).trim();
        pos = findWrapPos(text, width, 0);

        if (pos == -1)
        {
            sb.append(text);

            return sb;
        }

        if ( (text.length() > width) && (pos == nextLineTabStop - 1) ) 
        {
            pos = width;
        }

        // Check if we're stuck in an infinite loop by verifying that we're making progress
        if (pos <= nextLineTabStop) 
        {
            // Force a break by taking what fits on the current line
            sb.append(rtrim(text.substring(0, width))).append(defaultNewLine);
            text = padding + text.substring(width).trim();

            // If after trimming, the text is empty or just padding, we're done
            if (text.length() <= padding.length()) 
            {
                if (text.length() > padding.length()) 
                {
                    sb.append(text);
                }
                return sb;
            }
            pos = findWrapPos(text, width, 0);
            if (pos == -1) 
            {
                sb.append(text);
                return sb;
            }
        }

        sb.append(rtrim(text.substring(0, pos))).append(defaultNewLine);
    }
}

